-- ===== content_ready =====
INSERT INTO settings (key, value) VALUES
('email_template_content_ready_subject', 'Twoje reklamy są gotowe — zobacz materiały!'),
('email_template_content_ready_body', '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',Roboto,''Helvetica Neue'',Arial,sans-serif;background-color:#000000;"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#000000;padding:40px 20px;"><tr><td align="center"><table width="560" cellpadding="0" cellspacing="0" style="background-color:#0a0a0a;border-radius:12px;border:1px solid #262626;"><tr><td style="padding:48px 40px 40px 40px;"><p style="margin:0 0 8px 0;color:#a855f7;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:1px;">Materiały reklamowe</p><h1 style="margin:0 0 24px 0;color:#ffffff;font-size:28px;font-weight:600;line-height:1.3;">{{clientName}}, Twoje reklamy są gotowe</h1><p style="margin:0 0 24px 0;color:#a3a3a3;font-size:15px;line-height:1.6;">Przygotowałem dla Twojego sklepu <strong style="color:#ffffff;">kompletny pakiet reklamowy</strong> gotowy do uruchomienia na Meta Ads — zobacz podgląd w panelu klienta.</p><table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:32px;"><tr><td style="padding:14px 0;color:#d4d4d8;font-size:14px;line-height:1.5;">🔍 &nbsp; <strong style="color:#ffffff;">Analiza konkurencji</strong> — co robią inne marki w Twojej niszy</td></tr><tr><td style="padding:14px 0;border-top:1px solid #262626;color:#d4d4d8;font-size:14px;line-height:1.5;">✍️ &nbsp; <strong style="color:#ffffff;">5 wersji copy reklamowego</strong> — różne kąty, gotowe do publikacji</td></tr><tr><td style="padding:14px 0;border-top:1px solid #262626;color:#d4d4d8;font-size:14px;line-height:1.5;">🎨 &nbsp; <strong style="color:#ffffff;">5 kreacji graficznych 1:1</strong> z produktem i polskim tekstem</td></tr></table><table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:24px;"><tr><td align="center"><a href="{{projectUrl}}#content" style="display:inline-block;background:linear-gradient(135deg,#a855f7 0%,#06b6d4 100%);color:#ffffff;text-decoration:none;padding:16px 32px;border-radius:8px;font-size:14px;font-weight:600;text-align:center;">Zobacz materiały reklamowe →</a></td></tr></table><p style="margin:0;color:#737373;font-size:13px;line-height:1.5;">Kolejny krok: uruchamiam kampanię na Meta Ads. Dam znać, gdy reklamy zaczną się wyświetlać.</p></td></tr><tr><td style="padding:20px 40px;border-top:1px solid #262626;text-align:center;"><a href="https://tomekniedzwiecki.pl" style="color:#525252;font-size:12px;text-decoration:none;">tomekniedzwiecki.pl</a></td></tr></table></td></tr></table></body></html>')
ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;

-- ===== campaign_launched (override istniejący brzydki jasny na ciemny premium) =====
