('email_template_campaign_launched_subject', '🚀 Kampania {{brandName}} została uruchomiona!'),
('email_template_campaign_launched_body', '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',Roboto,''Helvetica Neue'',Arial,sans-serif;background-color:#000000;"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#000000;padding:40px 20px;"><tr><td align="center"><table width="560" cellpadding="0" cellspacing="0" style="background-color:#0a0a0a;border-radius:12px;border:1px solid #262626;"><tr><td style="padding:48px 40px 40px 40px;"><p style="margin:0 0 8px 0;color:#06b6d4;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:1px;">Kampania uruchomiona</p><h1 style="margin:0 0 24px 0;color:#ffffff;font-size:28px;font-weight:600;line-height:1.3;">{{clientName}}, Twoja kampania działa 🚀</h1><p style="margin:0 0 24px 0;color:#a3a3a3;font-size:15px;line-height:1.6;">Właśnie uruchomiłem Twoją kampanię reklamową dla <strong style="color:#ffffff;">{{brandName}}</strong> na Meta Ads. Reklamy zaczną się wyświetlać w ciągu najbliższych godzin.</p><div style="background-color:#0f172a;border:1px solid #1e3a8a;border-radius:8px;padding:20px;margin-bottom:32px;"><p style="margin:0 0 8px 0;color:#06b6d4;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:1px;">Co dalej?</p><p style="margin:0;color:#d4d4d8;font-size:14px;line-height:1.5;">Monitoruję wyniki codziennie. Pierwsze dane zobaczysz zwykle po 24-48 godzinach — prześlę Ci raport w panelu klienta gdy tylko będą dostępne.</p></div><table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:24px;"><tr><td align="center"><a href="{{projectUrl}}" style="display:inline-block;background:linear-gradient(135deg,#06b6d4 0%,#0891b2 100%);color:#ffffff;text-decoration:none;padding:16px 32px;border-radius:8px;font-size:14px;font-weight:600;text-align:center;">Zobacz panel klienta →</a></td></tr></table><p style="margin:0;color:#737373;font-size:13px;line-height:1.5;">Powodzenia z kampanią — trzymam kciuki za pierwsze konwersje!</p></td></tr><tr><td style="padding:20px 40px;border-top:1px solid #262626;text-align:center;"><a href="https://tomekniedzwiecki.pl" style="color:#525252;font-size:12px;text-decoration:none;">tomekniedzwiecki.pl</a></td></tr></table></td></tr></table></body></html>')
ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;

