INSERT INTO settings (key, value) VALUES
('email_template_ad_report_subject', 'Raport z kampanii {{project_name}} — {{period_from}} do {{period_to}}'),
('email_template_ad_report_body', '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',Roboto,''Helvetica Neue'',Arial,sans-serif;background-color:#000000;"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#000000;padding:40px 20px;"><tr><td align="center"><table width="560" cellpadding="0" cellspacing="0" style="background-color:#0a0a0a;border-radius:12px;border:1px solid #262626;"><tr><td style="padding:48px 40px 40px 40px;"><p style="margin:0 0 8px 0;color:#10b981;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:1px;">Raport z kampanii</p><h1 style="margin:0 0 8px 0;color:#ffffff;font-size:28px;font-weight:600;line-height:1.3;">{{client_name}}, oto Twoje wyniki</h1><p style="margin:0 0 32px 0;color:#737373;font-size:13px;">Okres: {{period_from}} — {{period_to}}</p><div style="background:linear-gradient(135deg,#059669 0%,#10b981 100%);border-radius:12px;padding:28px;margin-bottom:24px;text-align:center;"><p style="margin:0 0 8px 0;color:rgba(255,255,255,0.8);font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:2px;">ROAS</p><p style="margin:0;color:#ffffff;font-size:48px;font-weight:700;line-height:1;">{{roas}}x</p></div><table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:24px;"><tr><td width="50%" style="padding:16px;background-color:#18181b;border-radius:8px 0 0 0;border-right:1px solid #0a0a0a;"><p style="margin:0 0 4px 0;color:#737373;font-size:11px;text-transform:uppercase;letter-spacing:1px;">Wydatki</p><p style="margin:0;color:#ffffff;font-size:22px;font-weight:600;">{{spend}} {{currency}}</p></td><td width="50%" style="padding:16px;background-color:#18181b;border-radius:0 8px 0 0;"><p style="margin:0 0 4px 0;color:#737373;font-size:11px;text-transform:uppercase;letter-spacing:1px;">Przychód</p><p style="margin:0;color:#10b981;font-size:22px;font-weight:600;">{{revenue}} {{currency}}</p></td></tr><tr><td style="padding:16px;background-color:#141416;border-radius:0 0 0 8px;border-right:1px solid #0a0a0a;border-top:1px solid #0a0a0a;"><p style="margin:0 0 4px 0;color:#737373;font-size:11px;text-transform:uppercase;letter-spacing:1px;">Zakupy</p><p style="margin:0;color:#ffffff;font-size:22px;font-weight:600;">{{purchases}}</p></td><td style="padding:16px;background-color:#141416;border-radius:0 0 8px 0;border-top:1px solid #0a0a0a;"><p style="margin:0 0 4px 0;color:#737373;font-size:11px;text-transform:uppercase;letter-spacing:1px;">Kliknięcia</p><p style="margin:0;color:#ffffff;font-size:22px;font-weight:600;">{{clicks}}</p></td></tr></table><table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:24px;"><tr><td align="center"><a href="{{projectUrl}}" style="display:inline-block;background:linear-gradient(135deg,#10b981 0%,#059669 100%);color:#ffffff;text-decoration:none;padding:16px 32px;border-radius:8px;font-size:14px;font-weight:600;text-align:center;">Zobacz pełny raport →</a></td></tr></table><p style="margin:0;color:#737373;font-size:13px;line-height:1.5;">Kontynuuję optymalizację kampanii — kolejny raport otrzymasz za 7 dni.</p></td></tr><tr><td style="padding:20px 40px;border-top:1px solid #262626;text-align:center;"><a href="https://tomekniedzwiecki.pl" style="color:#525252;font-size:12px;text-decoration:none;">tomekniedzwiecki.pl</a></td></tr></table></td></tr></table></body></html>')
ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;
